const express = require('express');
const multer = require('multer');
const path = require('path');

const app = express();

// Configure multer with strict limits
const upload = multer({
  storage: multer.diskStorage({
    destination: (req, file, cb) => {
      cb(null, '/tmp/uploads/');
    },
    filename: (req, file, cb) => {
      const uniqueSuffix = Date.now() + '-' + Math.round(Math.random() * 1E9);
      cb(null, file.fieldname + '-' + uniqueSuffix + path.extname(file.originalname));
    }
  }),
  limits: {
    fileSize: 10 * 1024 * 1024, // 10MB max file size
    files: 5, // Maximum 5 files per request
    fields: 10, // Maximum 10 non-file fields
    parts: 15 // Maximum 15 parts (files + fields)
  },
  fileFilter: (req, file, cb) => {
    // Whitelist allowed file types
    const allowedTypes = /jpeg|jpg|png|pdf|docx/;
    const extname = allowedTypes.test(path.extname(file.originalname).toLowerCase());
    const mimetype = allowedTypes.test(file.mimetype);

    if (mimetype && extname) {
      return cb(null, true);
    } else {
      cb(new Error('Invalid file type. Only JPEG, PNG, PDF, and DOCX allowed.'));
    }
  }
});

// Apply limits to all requests
app.use(express.json({ limit: '10mb' }));
app.use(express.urlencoded({ limit: '10mb', extended: true }));

// File upload endpoint with error handling
app.post('/api/upload', upload.single('file'), (req, res) => {
  if (!req.file) {
    return res.status(400).json({ error: 'No file uploaded' });
  }

  res.json({
    message: 'File uploaded successfully',
    filename: req.file.filename,
    size: req.file.size
  });
});

// Error handling middleware for multer errors
app.use((err, req, res, next) => {
  if (err instanceof multer.MulterError) {
    if (err.code === 'LIMIT_FILE_SIZE') {
      return res.status(413).json({ error: 'File too large. Maximum size is 10MB' });
    }
    if (err.code === 'LIMIT_FILE_COUNT') {
      return res.status(400).json({ error: 'Too many files. Maximum is 5 files' });
    }
    if (err.code === 'LIMIT_UNEXPECTED_FILE') {
      return res.status(400).json({ error: 'Unexpected field name' });
    }
  }
  res.status(500).json({ error: err.message });
});

app.listen(3000, () => console.log('Server running on port 3000'));

const express = require('express');
const multer = require('multer');
const { BlobServiceClient } = require('@azure/storage-blob');
const { v4: uuidv4 } = require('uuid');
const stream = require('stream');

const app = express();

// Initialize Azure Blob Storage client
const connectionString = process.env.AZURE_STORAGE_CONNECTION_STRING;
const containerName = 'uploads';
const blobServiceClient = BlobServiceClient.fromConnectionString(connectionString);
const containerClient = blobServiceClient.getContainerClient(containerName);

// Custom storage engine that streams to Azure Blob
class AzureBlobStorage {
  constructor(options) {
    this.containerClient = options.containerClient;
  }

  _handleFile(req, file, cb) {
    const blobName = `${uuidv4()}-${file.originalname}`;
    const blockBlobClient = this.containerClient.getBlockBlobClient(blobName);

    // Create passthrough stream to count bytes
    let uploadedBytes = 0;
    const maxSize = 100 * 1024 * 1024; // 100MB limit

    const transformStream = new stream.Transform({
      transform(chunk, encoding, callback) {
        uploadedBytes += chunk.length;
        if (uploadedBytes > maxSize) {
          return callback(new Error('File size exceeds 100MB limit'));
        }
        callback(null, chunk);
      }
    });

    // Pipe file stream through size checker to Azure
    file.stream.pipe(transformStream);

    blockBlobClient.uploadStream(transformStream, 4 * 1024 * 1024, 20, {
      blobHTTPHeaders: { blobContentType: file.mimetype }
    })
      .then(uploadResult => {
        cb(null, {
          blobName: blobName,
          containerName: containerName,
          url: blockBlobClient.url,
          size: uploadedBytes
        });
      })
      .catch(err => {
        cb(err);
      });
  }

  _removeFile(req, file, cb) {
    const blockBlobClient = this.containerClient.getBlockBlobClient(file.blobName);
    blockBlobClient.delete()
      .then(() => cb(null))
      .catch(err => cb(err));
  }
}

const upload = multer({
  storage: new AzureBlobStorage({
    containerClient: containerClient
  }),
  limits: {
    fileSize: 100 * 1024 * 1024, // 100MB
    files: 1
  }
});

app.post('/api/upload', upload.single('file'), async (req, res) => {
  if (!req.file) {
    return res.status(400).json({ error: 'No file uploaded' });
  }

  res.json({
    message: 'File uploaded to Azure Blob Storage',
    blobName: req.file.blobName,
    url: req.file.url,
    size: req.file.size
  });
});

app.use((err, req, res, next) => {
  console.error('Upload error:', err);
  res.status(500).json({ error: err.message });
});

app.listen(3000);

from flask import Flask, request, jsonify
from werkzeug.utils import secure_filename
from flask_limiter import Limiter
from flask_limiter.util import get_remote_address
import os
from pathlib import Path

app = Flask(__name__)

# Configure maximum content length (10MB)
app.config['MAX_CONTENT_LENGTH'] = 10 * 1024 * 1024  # 10MB
app.config['UPLOAD_FOLDER'] = '/tmp/uploads'
app.config['ALLOWED_EXTENSIONS'] = {'png', 'jpg', 'jpeg', 'pdf', 'docx'}

# Initialize rate limiter
limiter = Limiter(
    app=app,
    key_func=get_remote_address,
    default_limits=["200 per day", "50 per hour"],
    storage_uri="redis://localhost:6379"
)

# Ensure upload directory exists
Path(app.config['UPLOAD_FOLDER']).mkdir(parents=True, exist_ok=True)

def allowed_file(filename):
    return '.' in filename and \
           filename.rsplit('.', 1)[1].lower() in app.config['ALLOWED_EXTENSIONS']

def get_file_size(file):
    """Get file size without loading entire file into memory"""
    file.seek(0, os.SEEK_END)
    size = file.tell()
    file.seek(0)
    return size

@app.errorhandler(413)
def request_entity_too_large(error):
    return jsonify({
        'error': 'File too large',
        'message': 'Maximum file size is 10MB'
    }), 413

@app.route('/api/upload', methods=['POST'])
@limiter.limit("10 per hour")  # Limit to 10 uploads per hour per IP
def upload_file():
    # Check if file is present in request
    if 'file' not in request.files:
        return jsonify({'error': 'No file part in request'}), 400

    file = request.files['file']

    if file.filename == '':
        return jsonify({'error': 'No file selected'}), 400

    if not allowed_file(file.filename):
        return jsonify({
            'error': 'Invalid file type',
            'allowed_types': list(app.config['ALLOWED_EXTENSIONS'])
        }), 400

    # Additional size check (Werkzeug already enforces MAX_CONTENT_LENGTH)
    file_size = get_file_size(file)
    if file_size > app.config['MAX_CONTENT_LENGTH']:
        return jsonify({
            'error': 'File size exceeds limit',
            'max_size_mb': app.config['MAX_CONTENT_LENGTH'] / (1024 * 1024)
        }), 413

    # Save file securely
    filename = secure_filename(file.filename)
    filepath = os.path.join(app.config['UPLOAD_FOLDER'], filename)

    # Stream file to disk in chunks to avoid memory issues
    try:
        file.save(filepath)
        return jsonify({
            'message': 'File uploaded successfully',
            'filename': filename,
            'size_bytes': file_size
        }), 201
    except Exception as e:
        return jsonify({'error': f'Upload failed: {str(e)}'}), 500

@app.route('/api/upload/streaming', methods=['POST'])
@limiter.limit("5 per hour")
def upload_file_streaming():
    """Stream large files to disk without loading into memory"""
    if 'file' not in request.files:
        return jsonify({'error': 'No file part'}), 400

    file = request.files['file']
    filename = secure_filename(file.filename)
    filepath = os.path.join(app.config['UPLOAD_FOLDER'], filename)

    # Stream file in chunks
    chunk_size = 4096  # 4KB chunks
    total_size = 0
    max_size = app.config['MAX_CONTENT_LENGTH']

    try:
        with open(filepath, 'wb') as f:
            while True:
                chunk = file.stream.read(chunk_size)
                if not chunk:
                    break
                total_size += len(chunk)
                if total_size > max_size:
                    # Clean up partial file
                    f.close()
                    os.remove(filepath)
                    return jsonify({'error': 'File too large'}), 413
                f.write(chunk)

        return jsonify({
            'message': 'File streamed successfully',
            'filename': filename,
            'size_bytes': total_size
        }), 201
    except Exception as e:
        if os.path.exists(filepath):
            os.remove(filepath)
        return jsonify({'error': f'Upload failed: {str(e)}'}), 500

if __name__ == '__main__':
    app.run(debug=False, host='0.0.0.0', port=5000)
